 1	import React from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { useTranslation } from 'react-i18next';
 4	import { DropdownItem } from '@patternfly/react-core';
 5	import {
 6	  K8sModel,
 7	  K8sResourceCommon,
 8	  useAccessReview,
 9	  useAnnotationsModal,
10	  useDeleteModal,
11	  useLabelsModal,
12	} from '@openshift-console/dynamic-plugin-sdk';
13	import { getReferenceForModel } from '../pipelines-overview/utils';
14	import {
15	  KEBAB_ACTION_DELETE_ID,
16	  KEBAB_ACTION_EDIT_ANNOTATIONS_ID,
17	  KEBAB_ACTION_EDIT_ID,
18	  KEBAB_ACTION_EDIT_LABELS_ID,
19	} from '../../consts';
20	
21	export const K8sCommonKebabMenu = (obj: K8sResourceCommon, model: K8sModel) => {
22	  const { t } = useTranslation('plugin__pipelines-console-plugin');
23	  const launchDeleteModal = useDeleteModal(obj);
24	  const launchAnnotationsModal = useAnnotationsModal(obj);
25	  const launchLabelsModal = useLabelsModal(obj);
26	  const navigate = useNavigate();
27	  const { name, namespace } = obj.metadata;
28	
29	  const canEditResource = useAccessReview({
30	    group: model.apiGroup,
31	    resource: model.plural,
32	    verb: 'update',
33	    name,
34	    namespace,
35	  });
36	  const canDeleteResource = useAccessReview({
37	    group: model.apiGroup,
38	    resource: model.plural,
39	    verb: 'delete',
40	    name,
41	    namespace,
42	  });
43	
44	  const editURL = namespace
45	    ? `/k8s/ns/${namespace}/${getReferenceForModel(model)}/${encodeURIComponent(
46	        name,
47	      )}/yaml`
48	    : `/k8s/cluster/${getReferenceForModel(model)}/${encodeURIComponent(
49	        name,
50	      )}/yaml`;
51	
52	  return [
53	    <DropdownItem
54	      key={KEBAB_ACTION_EDIT_LABELS_ID}
55	      component="button"
56	      onClick={launchLabelsModal}
57	      isDisabled={!canEditResource}
58	      data-test-action={KEBAB_ACTION_EDIT_LABELS_ID}
59	    >
60	      {t('Edit labels')}
61	    </DropdownItem>,
62	    <DropdownItem
63	      key={KEBAB_ACTION_EDIT_ANNOTATIONS_ID}
64	      component="button"
65	      onClick={() => launchAnnotationsModal()}
66	      isDisabled={!canEditResource[0]}
67	      data-test-action={KEBAB_ACTION_EDIT_ANNOTATIONS_ID}
68	    >
69	      {t('Edit annotations')}
70	    </DropdownItem>,
71	    <DropdownItem
72	      key={KEBAB_ACTION_EDIT_ID}
73	      component="button"
74	      onClick={() => navigate(editURL)}
75	      isDisabled={!canEditResource[0]}
76	      data-test-action={KEBAB_ACTION_EDIT_ID}
77	    >
78	      {t('Edit {{resourceKind}}', { resourceKind: model.kind })}
79	    </DropdownItem>,
80	    <DropdownItem
81	      key={KEBAB_ACTION_DELETE_ID}
82	      component="button"
83	      onClick={launchDeleteModal}
84	      isDisabled={!canDeleteResource[0]}
85	      data-test-action={KEBAB_ACTION_DELETE_ID}
86	    >
87	      {t('Delete {{resourceKind}}', { resourceKind: model.kind })}
88	    </DropdownItem>,
89	  ];
90	};

